import{_ as t}from"./plugin-vue_export-helper-c27b6911.js";import{r as i,o as p,c,e as n,b as e,d as o,a}from"./app-4a161474.js";const r={},s=e("h1",{id:"readme",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#readme","aria-hidden":"true"},"#"),o(" README")],-1),d=e("p",null,[o("鲁迅在狂人日记里曾经写道："),e("br"),e("strong",null,'我翻开历史一查，这历史没有年代。歪歪斜斜的每页上都写着“仁义道德”几个字，我横竖睡不着，仔细看了半夜，才从字缝里看出来，满本上都写着两个字“吃人"！')],-1),u=a('<div class="hint-container info"><p class="hint-container-title">相关信息</p><p>略</p></div><ul><li>人民群众日益增长的智商，和国家落后套路之间的矛盾</li></ul><blockquote><ul><li><p>我还是想说，农民，建筑工这两大群体为新中国做了特别大的贡献，但国家起来了却没有了属于他们的位置和养老退休金，甚至成为了某些人眼里贬义的职业，我真的很不能理解。</p></li><li><p>不是生产力让人劳碌，是商鞅五术必须让人劳碌，秦始皇才能高枕无忧</p></li><li><p>挺好奇一件事，我们的粮食问题早半个世纪就已经解决，建造的房子够住三十亿人，生产力已经翻了几十数百倍，但貌似大部分的人仍然和三十年前的人一样，为了最基础吃穿住用，死命辛苦半生，整天上班挨骂只为了每个月拿三四千块钱。<br> 按道理来说生产力应该确实是提升了，所以哪个环节出了问题</p><blockquote><p>问题出在分配环节。由于剥削的存在，这些东西从生产出来的那一刻，就已经决定了归属。</p></blockquote></li><li><p>这是最坏的时代，书读的越多，越感到无力改变现状。但也是最好的时代，不需要要像先辈一样面朝黄土背朝天。工作几个月的薪资完全可以躺大半年</p></li></ul></blockquote><p>毛泽东：我主张加一个罢工自由，要允许工人罢工。</p><blockquote><p>罢工是劳动者为了维护自身利益而集体拒绝工作的行为。那在中国如何合法罢工呢？答案就是在中国，公民罢工是违法行为。中华人民共和国1975年和1978年宪法规定，公民享有罢工自由权。在1982年，宪法完全取消了该规定，但也没有明文禁止罢工，只是如果你参与罢工，肯定违反中华人民共和国劳动法 。</p><p>但如果你是香港或者澳门居民，基本法规定 居民享有罢工的权利。总的来说，在社会主义社会，罢工是违法的，因为社会主义国家的工人和国家利益是一致的，罢工不符合人民的利益，所以罢工自由的规定不予保留。在资本主义社会，罢工是合法的，因为这是工人阶级反抗资本暴政的有力武器。罢工是工人和资本家谈判的筹码，因此资本主义国家才需要罢工，社会主义国家不需要罢工。</p></blockquote><p>中国法律为什么取消罢工自由：</p><blockquote><p>1975、1978年宪法都规定了这一权利，但是1982年宪法却没有规定，主要原因有三个：</p><p>一、防止再出来大规模动乱；</p><p>二、保障改革开放后以经济建设为中心的战略；</p><p>三、罢工就意味着存在国家与工人的利益冲突，这与社会主义理论是不符的。</p><p>“劳动者”具体指达到法定年龄，具有劳动能力，以从事某种社会劳动获得收入为主要生活来源，依据法律或合同的规定，在用人单位的管理下从事劳动并获取劳动报酬的自然人(中外自然人)。所以，劳动者只是公民的一部分。</p></blockquote><p>马克思共产道路有两条，一条是资本主义的自我改良走向共产主义，一条就是苏联和新中国的道路</p><blockquote><p>“我们的主要任务就是毫不停手地促使这种力量增长到超出政府统治制度所能支配的范围，不是要把这个日益增强的突击队在前哨战中消灭掉，而是要把它好好地保存到决战的那一天。”--恩格斯《法兰西阶级斗争》</p><ul><li>资本主义国家倒是体现出工人和农民的社会地位和力量，也是魔幻</li><li>马克思也认为未来社会主义与资本主义会融合，而且诞生在高度发达的资本主义社会，并且在严格的条件下国家才会消失，我认为这才是正解，社会主义是解放生产力，平均主义不行，计划经济更不行</li></ul></blockquote>',9);function _(b,h){const l=i("BiliBili");return p(),c("div",null,[s,d,n(l,{bvid:"BV1kt411o7C3"}),u])}const f=t(r,[["render",_],["__file","index.html.vue"]]);export{f as default};
